Here's a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file. The program assumes that the specified word is provided by the user as an input.

```cpp
#include <iostream>
#include <fstream>
#include <string>

using namespace std;

int main() {
    // Get the word to search for from the user
    string word;
    cout << "Enter the word to search for: ";
    getline(cin, word);

    // Open the input file for reading
    ifstream inputFile("example.txt");

    if (inputFile.is_open()) {
        // Read each line of the file
        string line;
        int count = 0;
        while (getline(inputFile, line)) {
            // Check if the current line contains the specified word
            size_t index = line.find(word);
            if (index!= string::npos) {
                // Increment the count if the word is found
                count++;
            }
        }

        // Close the input file and display the result
        inputFile.close();
        cout << "The word \"" << word << "\" was found " << count << " times in the file." << endl;
    } else {
        // Display an error message if the file cannot be opened
        cout << "Error opening the file." << endl;
    }

    return 0;
}
```

